// =================================================================
// Validate & Compute All Rows
// =================================================================
// Receives POST body with:
//   { results: [...], prompt_version: "baseline" }
// Each result has: request_id, title, company, pipeline_output
// Computes row arrays for all 5 Google Sheets tabs.
// =================================================================

const body = $input.first().json.body || $input.first().json;
const results = body.results || [];
const promptVersion = body.prompt_version || 'baseline';

if (!results.length) {
  return [{ json: {
    queryRows: [], coverageRows: [], metadataRows: [],
    trendsRows: [], feedbackRows: [],
    error: 'No results in payload'
  }}];
}

const allQueryRows = [];
const allCoverageRows = [];
const allMetadataRows = [];
const allTrendsRows = [];
const allFeedbackRows = [];

const now = new Date();
const dateStr = now.toISOString().slice(0, 10);
const dateTimeStr = `${dateStr} ${now.toTimeString().slice(0, 5)}`;

for (const result of results) {
  const output = result.pipeline_output;
  if (!output) continue;

  const rid = result.request_id || output.request_id || '';
  const title = result.title || output.request_title || '';
  const company = result.company || '';
  const stats = output.stats || {};
  const byCat = stats.by_category || {};

  // --- Queries tab ---
  for (const q of (output.valid_queries || [])) {
    allQueryRows.push({
      'Request ID': rid,
      'Request Title': title,
      'Company': company,
      'Query': q.query || '',
      'Result Count': q.result_count ?? '',
      'Category': q.category || '',
      'Status': 'valid',
      'SOI Covered': q.target_soi || '',
      'Rationale': q.rationale || '',
      'Relevance Passed': q.relevance_passed != null ? String(q.relevance_passed) : '',
      'Relevance Details': q.relevance_details || '',
      'Refinement Round': q.refinement_round || 0,
      'Original Query': q.original_query || ''
    });
  }

  for (const q of (output.unvalidated_queries || [])) {
    allQueryRows.push({
      'Request ID': rid,
      'Request Title': title,
      'Company': company,
      'Query': q.query || '',
      'Result Count': '',
      'Category': '',
      'Status': 'unvalidated',
      'SOI Covered': q.target_soi || '',
      'Rationale': q.rationale || '',
      'Relevance Passed': '',
      'Relevance Details': 'S2 API unreachable during validation',
      'Refinement Round': q.refinement_round || 0,
      'Original Query': q.original_query || ''
    });
  }

  // --- Coverage tab ---
  for (const cov of (output.soi_coverage || [])) {
    allCoverageRows.push({
      'Request ID': rid,
      'Request Title': title,
      'Solution of Interest': cov.soi || '',
      '# Queries': cov.num_queries || 0,
      'Best Query': cov.best_query || '',
      'Best Result Count': cov.best_result_count || 0
    });
  }

  // --- Run Metadata tab ---
  allMetadataRows.push({
    'Run ID': output.run_id || '',
    'Request ID': rid,
    'Request Title': title,
    'Company': company,
    'Started At': output.started_at || '',
    'Completed At': output.completed_at || '',
    'Model Used': output.model_used || '',
    'Total Generated': stats.total_generated || 0,
    'Valid': stats.valid || 0,
    'Unvalidated': stats.unvalidated || 0,
    'Rejected Broad': stats.rejected_too_broad || 0,
    'Rejected Irrelevant': stats.rejected_irrelevant || 0,
    'SOIs Covered': `${stats.sois_covered || 0}/${stats.sois_total || 0}`
  });

  // --- Performance Trends tab ---
  const total = stats.total_generated || 0;
  const valid = stats.valid || 0;
  const validRate = total > 0 ? valid / total : 0;
  const soisCovered = stats.sois_covered || 0;
  const soisTotal = stats.sois_total || 0;
  const coverageRate = soisTotal > 0 ? soisCovered / soisTotal : 0;

  // Count refined + recovery queries
  const validQueries = output.valid_queries || [];
  const refinedCount = validQueries.filter(q => (q.refinement_round || 0) > 0).length;
  const refinementRate = valid > 0 ? refinedCount / valid : 0;
  const recoveryCount = validQueries.filter(q => q.is_recovery === true).length;

  // Format as "57.1%" to match Python's f"{value:.1%}" output
  const fmtPct = (v) => `${(v * 100).toFixed(1)}%`;

  allTrendsRows.push({
    'Date': dateTimeStr,
    'Request ID': rid,
    'Request Title': title,
    'Company': company,
    'Total Generated': total,
    'Valid Queries': valid,
    'Valid Rate': fmtPct(validRate),
    'Unvalidated': stats.unvalidated || 0,
    'Rejected Broad': stats.rejected_too_broad || 0,
    'Rejected Irrelevant': stats.rejected_irrelevant || 0,
    'SOIs Covered': soisCovered,
    'SOIs Total': soisTotal,
    'Coverage Rate': fmtPct(coverageRate),
        'Specific': byCat.specific || 0,
    'Moderate': byCat.moderate || 0,
    'General': byCat.general || 0,
    'Refinement Rate': fmtPct(refinementRate),
    'Recovery Queries': recoveryCount,
    'Prompt Version': promptVersion
  });

  // --- Feedback tab ---
  const querySummary = `${valid} valid / ${total} total, ${soisCovered}/${soisTotal} SOIs`;

  // RUN header row
  allFeedbackRows.push({
    'Row Type': 'RUN',
    'Date': dateStr,
    'Request ID': rid,
    'Request Title': title,
    'Query': querySummary,
    'SOI': '',
    'Result Count': '',
    'Category': '',
    'Rating': '',
    'Notes': '',
    'Suggested Query': '',
    'Prompt Version': promptVersion,
    'Processed': ''
  });

  // Query detail rows
  for (const q of validQueries) {
    allFeedbackRows.push({
      'Row Type': '',
      'Date': dateStr,
      'Request ID': rid,
      'Request Title': '',
      'Query': q.query || '',
      'SOI': q.target_soi || '',
      'Result Count': q.result_count ?? '',
      'Category': q.category || '',
      'Rating': '',
      'Notes': '',
      'Suggested Query': '',
      'Prompt Version': promptVersion,
      'Processed': ''
    });
  }
}

return [{ json: {
  queryRows: allQueryRows,
  coverageRows: allCoverageRows,
  metadataRows: allMetadataRows,
  trendsRows: allTrendsRows,
  feedbackRows: allFeedbackRows
}}];

const data = $('Validate & Compute All Rows').first().json;
const rows = data.queryRows || [];
if (rows.length === 0) {
  return [{ json: { _empty: true } }];
}
return rows.map(row => ({ json: row }));

